import { TreeData, Person, Gender } from '../types';

/**
 * Helper to format date for GEDCOM (YYYY-MM-DD -> DD MMM YYYY)
 * Simple implementation: returns unmodified or basic format
 */
const formatGedcomDate = (dateStr?: string): string => {
  if (!dateStr) return '';
  const date = new Date(dateStr);
  if (isNaN(date.getTime())) return dateStr;

  const day = date.getDate();
  const month = date.toLocaleString('default', { month: 'short' }).toUpperCase();
  const year = date.getFullYear();
  return `${day} ${month} ${year}`;
};

/**
 * Generates a GEDCOM 5.5.1 compatible string from TreeData
 */
export const generateGedcom = (data: TreeData): string => {
  const { people } = data;
  const lines: string[] = [];
  const peopleList = Object.values(people);

  // 1. HEAD
  lines.push('0 HEAD');
  lines.push('1 SOUR AncestryAI');
  lines.push('1 GEDC');
  lines.push('2 VERS 5.5.1');
  lines.push('2 FORM LINEAGE-LINKED');
  lines.push('1 CHAR UTF-8');

  // 2. INDIVIDUALS (INDI)
  peopleList.forEach(person => {
    lines.push(`0 @I${person.id}@ INDI`);
    lines.push(`1 NAME ${person.firstName} /${person.lastName}/`);
    lines.push(`2 GIVN ${person.firstName}`);
    lines.push(`2 SURN ${person.lastName}`);
    lines.push(`1 SEX ${person.gender === Gender.Male ? 'M' : person.gender === Gender.Female ? 'F' : 'U'}`);

    if (person.birthDate) {
      lines.push('1 BIRT');
      lines.push(`2 DATE ${formatGedcomDate(person.birthDate)}`);
      if (person.birthPlace) lines.push(`2 PLAC ${person.birthPlace}`);
    }

    if (person.deathDate) {
      lines.push('1 DEAT');
      lines.push(`2 DATE ${formatGedcomDate(person.deathDate)}`);
    }

    if (person.bio) {
      lines.push('1 NOTE ' + person.bio.replace(/\n/g, ' '));
    }

    // Link to families where this person is a child
    if (person.fatherId || person.motherId) {
       // We construct a family ID based on parents. 
       // Logic: Family ID is F_{FatherID}_{MotherID}
       // If one is missing, we use 'U' (Unknown)
       const fid = `F_${person.fatherId || 'U'}_${person.motherId || 'U'}`;
       lines.push(`1 FAMC @${fid}@`);
    }

    // Link to families where this person is a spouse
    // We will handle FAMS lines by iterating known spouses
    person.spouseIds.forEach(spouseId => {
        // To avoid duplicate family records, we sort IDs to make a unique key
        const ids = [person.id, spouseId].sort();
        const fid = `F_${ids[0]}_${ids[1]}`;
        lines.push(`1 FAMS @${fid}@`);
    });
  });

  // 3. FAMILIES (FAM)
  // We need to deduce families. A family exists if:
  // a) A child has parents
  // b) Two people are spouses

  const families = new Map<string, { husb?: string, wife?: string, children: string[] }>();

  // Helper to get/create family
  const getFamily = (key: string) => {
      if (!families.has(key)) {
          families.set(key, { children: [] });
      }
      return families.get(key)!;
  };

  peopleList.forEach(person => {
      // Case A: Child relationship
      if (person.fatherId || person.motherId) {
          const fKey = `F_${person.fatherId || 'U'}_${person.motherId || 'U'}`;
          const fam = getFamily(fKey);
          fam.children.push(person.id);
          if (person.fatherId) fam.husb = person.fatherId;
          if (person.motherId) fam.wife = person.motherId;
      }

      // Case B: Spouse relationship
      // Note: This might overlap with Case A if they have children, 
      // but if they have NO children, we still need a family record.
      person.spouseIds.forEach(spouseId => {
           const ids = [person.id, spouseId].sort();
           const fKey = `F_${ids[0]}_${ids[1]}`;
           const fam = getFamily(fKey);

           // Assign Husband/Wife based on gender if possible, otherwise by sort order
           // This is a simplification; robust logic checks gender of both
           if (person.gender === Gender.Male) fam.husb = person.id;
           else if (person.gender === Gender.Female) fam.wife = person.id;

           const spouse = people[spouseId];
           if (spouse) {
               if (spouse.gender === Gender.Male) fam.husb = spouseId;
               else if (spouse.gender === Gender.Female) fam.wife = spouseId;
           }

           // Fallback if genders are same or unknown
           if (!fam.husb && !fam.wife) {
               fam.husb = ids[0];
               fam.wife = ids[1];
           }
      });
  });

  // Output FAM records
  families.forEach((fam, key) => {
      lines.push(`0 @${key}@ FAM`);
      if (fam.husb) lines.push(`1 HUSB @I${fam.husb}@`);
      if (fam.wife) lines.push(`1 WIFE @I${fam.wife}@`);
      fam.children.forEach(childId => {
          lines.push(`1 CHIL @I${childId}@`);
      });
  });

  // 4. TRAILER
  lines.push('0 TRLR');

  return lines.join('\n');
};

import React, { useState, useEffect } from 'react';
import { Person, Gender } from '../types';
import { generateBio } from '../services/geminiService';
import { Wand2, Save, X, Loader2, Heart, Trash2, Plus } from 'lucide-react';

interface EditorPanelProps {
  person: Person | null;
  onSave: (person: Person) => void;
  onCancel: () => void;
  allPeople: Person[];
}

export const EditorPanel: React.FC<EditorPanelProps> = ({ person, onSave, onCancel, allPeople }) => {
  const [formData, setFormData] = useState<Partial<Person>>({
    gender: Gender.Male,
    firstName: '',
    lastName: '',
    spouseIds: [],
    childrenIds: [],
  });

  const [generatingBio, setGeneratingBio] = useState(false);

  useEffect(() => {
    if (person) {
      setFormData({ ...person });
    } else {
      // Reset for new entry
      setFormData({
        id: crypto.randomUUID(),
        gender: Gender.Male,
        firstName: '',
        lastName: '',
        spouseIds: [],
        childrenIds: [],
        bio: '',
      });
    }
  }, [person]);

  const handleChange = (field: keyof Person, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const handleGenerateBio = async () => {
    if (!formData.firstName || !formData.lastName) return;
    setGeneratingBio(true);
    try {
      const bio = await generateBio(formData as Person);
      handleChange('bio', bio);
    } finally {
      setGeneratingBio(false);
    }
  };

  const addSpouse = (spouseId: string) => {
    if (!spouseId) return;
    const currentSpouses = formData.spouseIds || [];
    if (!currentSpouses.includes(spouseId)) {
        handleChange('spouseIds', [...currentSpouses, spouseId]);
    }
  };

  const removeSpouse = (spouseId: string) => {
    const currentSpouses = formData.spouseIds || [];
    handleChange('spouseIds', currentSpouses.filter(id => id !== spouseId));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.firstName && formData.lastName) {
        // Ensure arrays are initialized
        const cleanData = {
            ...formData,
            spouseIds: formData.spouseIds || [],
            childrenIds: formData.childrenIds || [],
        }
        onSave(cleanData as Person);
    }
  };

  // Filter potential spouses (exclude self and already selected)
  const availableSpouses = allPeople.filter(p => 
      p.id !== formData.id && 
      !formData.spouseIds?.includes(p.id)
  );

  return (
    <div className="h-full bg-slate-800 border-l border-slate-700 p-6 overflow-y-auto no-scrollbar">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-xl font-bold text-white">
          {person ? 'Edit Person' : 'Add Person'}
        </h2>
        <button onClick={onCancel} className="text-slate-400 hover:text-white">
          <X size={24} />
        </button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-4">
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-xs font-medium text-slate-400 mb-1">First Name</label>
            <input
              type="text"
              required
              className="w-full bg-slate-900 border border-slate-600 rounded px-3 py-2 text-white focus:border-brand-500 outline-none"
              value={formData.firstName || ''}
              onChange={e => handleChange('firstName', e.target.value)}
            />
          </div>
          <div>
            <label className="block text-xs font-medium text-slate-400 mb-1">Last Name</label>
            <input
              type="text"
              required
              className="w-full bg-slate-900 border border-slate-600 rounded px-3 py-2 text-white focus:border-brand-500 outline-none"
              value={formData.lastName || ''}
              onChange={e => handleChange('lastName', e.target.value)}
            />
          </div>
        </div>

        <div>
          <label className="block text-xs font-medium text-slate-400 mb-1">Gender</label>
          <select
            className="w-full bg-slate-900 border border-slate-600 rounded px-3 py-2 text-white focus:border-brand-500 outline-none"
            value={formData.gender || Gender.Male}
            onChange={e => handleChange('gender', e.target.value as Gender)}
          >
            <option value={Gender.Male}>Male</option>
            <option value={Gender.Female}>Female</option>
            <option value={Gender.Other}>Other</option>
          </select>
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-xs font-medium text-slate-400 mb-1">Birth Date</label>
            <input
              type="date"
              className="w-full bg-slate-900 border border-slate-600 rounded px-3 py-2 text-white focus:border-brand-500 outline-none"
              value={formData.birthDate || ''}
              onChange={e => handleChange('birthDate', e.target.value)}
            />
          </div>
          <div>
            <label className="block text-xs font-medium text-slate-400 mb-1">Death Date</label>
            <input
              type="date"
              className="w-full bg-slate-900 border border-slate-600 rounded px-3 py-2 text-white focus:border-brand-500 outline-none"
              value={formData.deathDate || ''}
              onChange={e => handleChange('deathDate', e.target.value)}
            />
          </div>
        </div>

        {/* Spouses Section */}
        <div className="bg-slate-900/50 p-3 rounded border border-slate-700">
            <label className="block text-xs font-medium text-slate-400 mb-2 flex items-center gap-2">
                <Heart size={12} className="text-pink-500" /> Spouses / Partners
            </label>

            <div className="space-y-2 mb-2">
                {formData.spouseIds?.map(spouseId => {
                    const spouse = allPeople.find(p => p.id === spouseId);
                    return (
                        <div key={spouseId} className="flex justify-between items-center bg-slate-800 p-2 rounded text-sm">
                            <span className="text-white">{spouse ? `${spouse.firstName} ${spouse.lastName}` : 'Unknown'}</span>
                            <button 
                                type="button"
                                onClick={() => removeSpouse(spouseId)}
                                className="text-red-400 hover:text-red-300"
                            >
                                <Trash2 size={14} />
                            </button>
                        </div>
                    );
                })}
            </div>

            <div className="flex gap-2">
                <select 
                    className="flex-1 bg-slate-900 border border-slate-600 rounded px-2 py-1 text-sm text-white focus:border-brand-500 outline-none"
                    onChange={(e) => {
                        addSpouse(e.target.value);
                        e.target.value = ''; // Reset select
                    }}
                >
                    <option value="">+ Add Spouse...</option>
                    {availableSpouses.map(p => (
                        <option key={p.id} value={p.id}>{p.firstName} {p.lastName}</option>
                    ))}
                </select>
            </div>
        </div>

        <div>
           <label className="block text-xs font-medium text-slate-400 mb-1">Father</label>
           <select 
             className="w-full bg-slate-900 border border-slate-600 rounded px-3 py-2 text-white focus:border-brand-500 outline-none"
             value={formData.fatherId || ''}
             onChange={e => handleChange('fatherId', e.target.value || null)}
           >
             <option value="">Unknown</option>
             {allPeople.filter(p => p.id !== formData.id && p.gender === Gender.Male).map(p => (
               <option key={p.id} value={p.id}>{p.firstName} {p.lastName}</option>
             ))}
           </select>
        </div>

        <div>
           <label className="block text-xs font-medium text-slate-400 mb-1">Mother</label>
           <select 
             className="w-full bg-slate-900 border border-slate-600 rounded px-3 py-2 text-white focus:border-brand-500 outline-none"
             value={formData.motherId || ''}
             onChange={e => handleChange('motherId', e.target.value || null)}
           >
             <option value="">Unknown</option>
             {allPeople.filter(p => p.id !== formData.id && p.gender === Gender.Female).map(p => (
               <option key={p.id} value={p.id}>{p.firstName} {p.lastName}</option>
             ))}
           </select>
        </div>

        <div>
          <div className="flex justify-between items-center mb-1">
            <label className="block text-xs font-medium text-slate-400">Biography</label>
            <button
              type="button"
              onClick={handleGenerateBio}
              disabled={generatingBio || !formData.firstName}
              className="text-xs text-brand-400 flex items-center gap-1 hover:text-brand-300 disabled:opacity-50"
            >
              {generatingBio ? <Loader2 size={12} className="animate-spin"/> : <Wand2 size={12} />}
              Auto-Write
            </button>
          </div>
          <textarea
            className="w-full bg-slate-900 border border-slate-600 rounded px-3 py-2 text-white focus:border-brand-500 outline-none h-32 text-sm"
            value={formData.bio || ''}
            onChange={e => handleChange('bio', e.target.value)}
          />
        </div>

        <div className="pt-4 flex gap-3">
            <button
              type="submit"
              className="flex-1 bg-brand-600 hover:bg-brand-500 text-white py-2 rounded font-medium flex justify-center items-center gap-2"
            >
              <Save size={18} /> Save Record
            </button>
        </div>
      </form>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { NAV_ITEMS } from './constants';
import { TreeData, Person, ViewMode, Gender } from './types';
import { TreeVisualizer } from './components/TreeVisualizer';
import { EditorPanel } from './components/EditorPanel';
import { SmartAdd } from './components/SmartAdd';
import { LoginScreen } from './components/LoginScreen';
import { authService, User } from './services/authService';
import { storageService } from './services/storageService';
import { generateGedcom } from './services/gedcomService';
import { Leaf, Plus, PanelLeftClose, PanelLeft, LogOut, Loader2, Download } from 'lucide-react';
import clsx from 'clsx';

function App() {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  // Tree State
  const [treeData, setTreeData] = useState<TreeData | null>(null);
  const [activeView, setActiveView] = useState<ViewMode>('tree');
  const [selectedPersonId, setSelectedPersonId] = useState<string | null>(null);
  const [isSidebarOpen, setIsSidebarOpen] = useState(true);

  // Initialize Auth
  useEffect(() => {
    const currentUser = authService.getCurrentUser();
    setUser(currentUser);
    setLoading(false);
  }, []);

  // Initialize Data when User is present
  useEffect(() => {
    if (user) {
      loadData();
    }
  }, [user]);

  const loadData = async () => {
    try {
      const data = await storageService.loadTree();
      setTreeData(data);
    } catch (e) {
      console.error("Failed to load tree data", e);
    }
  };

  // Helper to get array of people
  const peopleList = treeData ? (Object.values(treeData.people) as Person[]) : [];

  const handleSavePerson = async (updatedPerson: Person) => {
    if (!treeData) return;

    // Get the previous version of this person (if exists) to check for removed spouses
    const oldPerson = treeData.people[updatedPerson.id];
    const oldSpouseIds = oldPerson ? oldPerson.spouseIds : [];
    const newSpouseIds = updatedPerson.spouseIds;

    // 1. Identify Removed Spouses: IDs in old but not in new
    const removedSpouseIds = oldSpouseIds.filter(id => !newSpouseIds.includes(id));

    // 2. Identify Added Spouses: IDs in new but not in old
    const addedSpouseIds = newSpouseIds.filter(id => !oldSpouseIds.includes(id));

    // Optimistic Update
    setTreeData(prev => {
      if (!prev) return null;
      const newData = { ...prev };

      // Update Main Person
      newData.people[updatedPerson.id] = updatedPerson;

      // Update Parent links (Children pointers)
      if (updatedPerson.fatherId && newData.people[updatedPerson.fatherId]) {
         const father = newData.people[updatedPerson.fatherId];
         if (!father.childrenIds.includes(updatedPerson.id)) {
            father.childrenIds = [...father.childrenIds, updatedPerson.id];
            storageService.savePerson(father); // Background save
         }
      }
      if (updatedPerson.motherId && newData.people[updatedPerson.motherId]) {
         const mother = newData.people[updatedPerson.motherId];
         if (!mother.childrenIds.includes(updatedPerson.id)) {
            mother.childrenIds = [...mother.childrenIds, updatedPerson.id];
            storageService.savePerson(mother); // Background save
         }
      }

      // Handle Reciprocal Spouse Unlinking
      removedSpouseIds.forEach(exSpouseId => {
          const exSpouse = newData.people[exSpouseId];
          if (exSpouse) {
              exSpouse.spouseIds = exSpouse.spouseIds.filter(id => id !== updatedPerson.id);
              storageService.savePerson(exSpouse);
          }
      });

      // Handle Reciprocal Spouse Linking
      addedSpouseIds.forEach(newSpouseId => {
          const newSpouse = newData.people[newSpouseId];
          if (newSpouse && !newSpouse.spouseIds.includes(updatedPerson.id)) {
              newSpouse.spouseIds = [...newSpouse.spouseIds, updatedPerson.id];
              storageService.savePerson(newSpouse);
          }
      });

      return newData;
    });

    // Persist Main Person to DB
    await storageService.savePerson(updatedPerson);

    setSelectedPersonId(null);
    setActiveView('tree');
  };

  const handleSmartAdd = async (partialPerson: Partial<Person>) => {
    const newPerson: Person = {
      id: crypto.randomUUID(),
      firstName: partialPerson.firstName || 'Unknown',
      lastName: partialPerson.lastName || 'Unknown',
      gender: (partialPerson.gender as Gender) || Gender.Other,
      spouseIds: [],
      childrenIds: [],
      birthDate: partialPerson.birthDate,
      deathDate: partialPerson.deathDate,
      birthPlace: partialPerson.birthPlace,
      bio: partialPerson.bio,
      fatherId: null,
      motherId: null,
    };

    // Optimistic update
    setTreeData(prev => {
        if(!prev) return null;
        return {
            ...prev,
            people: { ...prev.people, [newPerson.id]: newPerson }
        }
    });

    // Save to DB immediately so it exists for editing
    await storageService.savePerson(newPerson);

    setSelectedPersonId(newPerson.id);
    setActiveView('editor');
  };

  const handleLogout = async () => {
    await authService.logout();
    setUser(null);
    setTreeData(null);
  };

  const handleSelectPerson = (id: string) => {
    setSelectedPersonId(id);
    setActiveView('editor');
  };

  const createNewPerson = () => {
    setSelectedPersonId(null);
    setActiveView('editor');
  };

  const handleExportGedcom = () => {
      if (!treeData) return;
      const gedcomString = generateGedcom(treeData);
      const blob = new Blob([gedcomString], { type: 'text/plain' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `family_tree_${new Date().toISOString().split('T')[0]}.ged`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
      URL.revokeObjectURL(url);
  };

  if (loading) {
    return (
      <div className="h-screen w-full flex items-center justify-center bg-slate-950 text-brand-500">
        <Loader2 size={48} className="animate-spin" />
      </div>
    );
  }

  if (!user) {
    return <LoginScreen onLogin={() => setUser(authService.getCurrentUser())} />;
  }

  if (!treeData) {
      return (
        <div className="h-screen w-full flex flex-col items-center justify-center bg-slate-950 text-slate-400 gap-4">
            <Loader2 size={32} className="animate-spin text-brand-500" />
            <p>Loading your family history...</p>
        </div>
      );
  }

  return (
    <div className="flex h-screen bg-slate-950 text-slate-200 font-sans overflow-hidden">
      {/* Sidebar Navigation */}
      <div className={clsx("flex flex-col border-r border-slate-800 bg-slate-900 transition-all duration-300", isSidebarOpen ? "w-64" : "w-16")}>
        <div className="p-4 border-b border-slate-800 flex items-center gap-3">
          <div className="bg-brand-600 p-2 rounded-lg shrink-0">
            <Leaf size={24} className="text-white" />
          </div>
          {isSidebarOpen && <h1 className="font-bold text-xl tracking-tight text-white whitespace-nowrap">AncestryAI</h1>}
        </div>

        <nav className="flex-1 p-2 space-y-1">
          {NAV_ITEMS.map(item => (
            <button
              key={item.id}
              onClick={() => setActiveView(item.id as ViewMode)}
              className={clsx(
                "w-full flex items-center gap-3 px-3 py-3 rounded-lg transition-colors",
                activeView === item.id
                  ? "bg-brand-900/50 text-brand-400 border border-brand-800"
                  : "text-slate-400 hover:bg-slate-800 hover:text-slate-200"
              )}
              title={!isSidebarOpen ? item.label : undefined}
            >
              <span className="shrink-0">{item.icon}</span>
              {isSidebarOpen && <span className="font-medium whitespace-nowrap">{item.label}</span>}
            </button>
          ))}

          <div className="border-t border-slate-800 my-2"></div>

           <button
              onClick={handleExportGedcom}
              className="w-full flex items-center gap-3 px-3 py-3 rounded-lg transition-colors text-slate-400 hover:bg-slate-800 hover:text-slate-200"
              title={!isSidebarOpen ? "Export GEDCOM" : undefined}
            >
              <span className="shrink-0"><Download size={20} /></span>
              {isSidebarOpen && <span className="font-medium whitespace-nowrap">Export GEDCOM</span>}
            </button>

        </nav>

        <div className="p-4 border-t border-slate-800">
            <button 
              onClick={createNewPerson}
              className={clsx(
                  "w-full flex items-center justify-center gap-2 bg-slate-800 hover:bg-brand-600 text-white p-3 rounded-lg transition-all mb-4",
                  !isSidebarOpen && "aspect-square p-0"
              )}
              title="Add Person Manually"
            >
                <Plus size={20} />
                {isSidebarOpen && <span className="whitespace-nowrap">Add Member</span>}
            </button>

            <button 
              onClick={() => setIsSidebarOpen(!isSidebarOpen)}
              className="w-full flex justify-center p-2 text-slate-500 hover:text-slate-300"
            >
              {isSidebarOpen ? <PanelLeftClose size={20}/> : <PanelLeft size={20} />}
            </button>
        </div>
      </div>

      {/* Main Content Area */}
      <main className="flex-1 flex flex-col h-full overflow-hidden relative">
        <header className="h-16 border-b border-slate-800 bg-slate-900/50 backdrop-blur flex items-center justify-between px-6 shrink-0">
            <h2 className="text-lg font-medium text-white">
                {activeView === 'tree' && 'Family Tree Visualization'}
                {activeView === 'editor' && 'Record Management'}
                {activeView === 'smart-add' && 'AI Quick Import'}
            </h2>
            <div className="flex items-center gap-4">
                <div className="flex items-center gap-3 pr-4 border-r border-slate-800">
                   <div className="text-right hidden sm:block">
                       <div className="text-sm font-medium text-white">{user.name}</div>
                       <div className="text-xs text-slate-400">Free Plan</div>
                   </div>
                   <img src={user.photoUrl} alt="User" className="w-8 h-8 rounded-full border border-slate-600" />
                </div>
                <button 
                    onClick={handleLogout}
                    className="text-slate-400 hover:text-white transition-colors"
                    title="Sign Out"
                >
                    <LogOut size={20} />
                </button>
            </div>
        </header>

        <div className="flex-1 overflow-hidden p-6 relative">
             {activeView === 'tree' && (
