import { Person, TreeData } from '../types';
import { INITIAL_DATA } from '../constants';

const DB_NAME = 'FamilyTreeAI_DB';
const DB_VERSION = 1;
const STORE_NAME = 'people';

// Helper to open database
const openDB = (): Promise<IDBDatabase> => {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(DB_NAME, DB_VERSION);

    request.onerror = () => reject(request.error);

    request.onupgradeneeded = (event) => {
      const db = (event.target as IDBOpenDBRequest).result;
      if (!db.objectStoreNames.contains(STORE_NAME)) {
        db.createObjectStore(STORE_NAME, { keyPath: 'id' });
      }
    };

    request.onsuccess = () => resolve(request.result);
  });
};

export const storageService = {
  // Load all people to reconstruct the tree
  async loadTree(): Promise<TreeData> {
    const db = await openDB();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(STORE_NAME, 'readonly');
      const store = transaction.objectStore(STORE_NAME);
      const request = store.getAll();

      request.onsuccess = () => {
        const peopleList = request.result as Person[];

        // If DB is empty, seed it with initial data
        if (peopleList.length === 0) {
          this.seedData().then(resolve).catch(reject);
        } else {
          // Convert array back to Record<string, Person>
          const peopleMap: Record<string, Person> = {};
          peopleList.forEach(p => peopleMap[p.id] = p);

          resolve({
            rootId: '1', // In a real app, this might be stored in a separate 'meta' store
            people: peopleMap
          });
        }
      };

      request.onerror = () => reject(request.error);
    });
  },

  // Save or Update a single person
  async savePerson(person: Person): Promise<void> {
    const db = await openDB();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(STORE_NAME, 'readwrite');
      const store = transaction.objectStore(STORE_NAME);
      const request = store.put(person);

      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  },

  // Seed initial data if empty
  async seedData(): Promise<TreeData> {
    const db = await openDB();
    return new Promise((resolve, reject) => {
      const transaction = db.transaction(STORE_NAME, 'readwrite');
      const store = transaction.objectStore(STORE_NAME);

      const people = Object.values(INITIAL_DATA.people);
      let completed = 0;

      people.forEach(person => {
        store.put(person);
        completed++;
      });

      transaction.oncomplete = () => resolve(INITIAL_DATA);
      transaction.onerror = () => reject(transaction.error);
    });
  },

  // Clear database (helper for debugging/logout if needed)
  async clearDatabase(): Promise<void> {
      const db = await openDB();
      return new Promise((resolve, reject) => {
          const transaction = db.transaction(STORE_NAME, 'readwrite');
          const store = transaction.objectStore(STORE_NAME);
          store.clear();
          transaction.oncomplete = () => resolve();
      });
  }
};

import { TreeData, Person, Gender } from '../types';

/**
 * Helper to format date for GEDCOM (YYYY-MM-DD -> DD MMM YYYY)
 * Simple implementation: returns unmodified or basic format
 */
const formatGedcomDate = (dateStr?: string): string => {
  if (!dateStr) return '';
  const date = new Date(dateStr);
  if (isNaN(date.getTime())) return dateStr;

  const day = date.getDate();
  const month = date.toLocaleString('default', { month: 'short' }).toUpperCase();
  const year = date.getFullYear();
  return `${day} ${month} ${year}`;
};

/**
 * Generates a GEDCOM 5.5.1 compatible string from TreeData
 */
export const generateGedcom = (data: TreeData): string => {
  const { people } = data;
  const lines: string[] = [];
  const peopleList = Object.values(people);

  // 1. HEAD
  lines.push('0 HEAD');
  lines.push('1 SOUR FamilyTreeAI');
  lines.push('1 GEDC');
  lines.push('2 VERS 5.5.1');
  lines.push('2 FORM LINEAGE-LINKED');
  lines.push('1 CHAR UTF-8');

  // 2. INDIVIDUALS (INDI)
  peopleList.forEach(person => {
    lines.push(`0 @I${person.id}@ INDI`);
    lines.push(`1 NAME ${person.firstName} /${person.lastName}/`);
    lines.push(`2 GIVN ${person.firstName}`);
    lines.push(`2 SURN ${person.lastName}`);
    lines.push(`1 SEX ${person.gender === Gender.Male ? 'M' : person.gender === Gender.Female ? 'F' : 'U'}`);

    if (person.birthDate) {
      lines.push('1 BIRT');
      lines.push(`2 DATE ${formatGedcomDate(person.birthDate)}`);
      if (person.birthPlace) lines.push(`2 PLAC ${person.birthPlace}`);
    }

    if (person.deathDate) {
      lines.push('1 DEAT');
      lines.push(`2 DATE ${formatGedcomDate(person.deathDate)}`);
    }

    if (person.bio) {
      lines.push('1 NOTE ' + person.bio.replace(/\n/g, ' '));
    }

    // Link to families where this person is a child
    if (person.fatherId || person.motherId) {
       // We construct a family ID based on parents. 
       // Logic: Family ID is F_{FatherID}_{MotherID}
       // If one is missing, we use 'U' (Unknown)
       const fid = `F_${person.fatherId || 'U'}_${person.motherId || 'U'}`;
       lines.push(`1 FAMC @${fid}@`);
    }

    // Link to families where this person is a spouse
    // We will handle FAMS lines by iterating known spouses
    person.spouseIds.forEach(spouseId => {
        // To avoid duplicate family records, we sort IDs to make a unique key
        const ids = [person.id, spouseId].sort();
        const fid = `F_${ids[0]}_${ids[1]}`;
        lines.push(`1 FAMS @${fid}@`);
    });
  });

  // 3. FAMILIES (FAM)
  // We need to deduce families. A family exists if:
  // a) A child has parents
  // b) Two people are spouses

  const families = new Map<string, { husb?: string, wife?: string, children: string[] }>();

  // Helper to get/create family
  const getFamily = (key: string) => {
      if (!families.has(key)) {
          families.set(key, { children: [] });
      }
      return families.get(key)!;
  };

  peopleList.forEach(person => {
      // Case A: Child relationship
      if (person.fatherId || person.motherId) {
          const fKey = `F_${person.fatherId || 'U'}_${person.motherId || 'U'}`;
          const fam = getFamily(fKey);
          fam.children.push(person.id);
          if (person.fatherId) fam.husb = person.fatherId;
          if (person.motherId) fam.wife = person.motherId;
      }

      // Case B: Spouse relationship
      // Note: This might overlap with Case A if they have children, 
      // but if they have NO children, we still need a family record.
      person.spouseIds.forEach(spouseId => {
           const ids = [person.id, spouseId].sort();
           const fKey = `F_${ids[0]}_${ids[1]}`;
           const fam = getFamily(fKey);

           // Assign Husband/Wife based on gender if possible, otherwise by sort order
           // This is a simplification; robust logic checks gender of both
           if (person.gender === Gender.Male) fam.husb = person.id;
           else if (person.gender === Gender.Female) fam.wife = person.id;

           const spouse = people[spouseId];
           if (spouse) {
               if (spouse.gender === Gender.Male) fam.husb = spouseId;
               else if (spouse.gender === Gender.Female) fam.wife = spouseId;
           }

           // Fallback if genders are same or unknown
           if (!fam.husb && !fam.wife) {
               fam.husb = ids[0];
               fam.wife = ids[1];
           }
      });
  });

  // Output FAM records
  families.forEach((fam, key) => {
      lines.push(`0 @${key}@ FAM`);
      if (fam.husb) lines.push(`1 HUSB @I${fam.husb}@`);
      if (fam.wife) lines.push(`1 WIFE @I${fam.wife}@`);
      fam.children.forEach(childId => {
          lines.push(`1 CHIL @I${childId}@`);
      });
  });

  // 4. TRAILER
  lines.push('0 TRLR');

  return lines.join('\n');
};

export enum Gender {
  Male = 'Male',
  Female = 'Female',
  Other = 'Other'
}

export interface Person {
  id: string;
  firstName: string;
  lastName: string;
  gender: Gender;
  birthDate?: string;
  birthPlace?: string;
  deathDate?: string;
  deathPlace?: string;
  bio?: string;
  photo?: string; // Base64 string or URL
  // Relationships
  fatherId?: string | null;
  motherId?: string | null;
  spouseIds: string[];
  childrenIds: string[];
}

export interface TreeData {
  people: Record<string, Person>;
  rootId: string; // The primary ancestor to start the visualization from
}

export interface D3NodeDatum {
  name: string;
  attributes: {
    id: string;
    gender: Gender;
    birthDate?: string;
    birthPlace?: string;
    deathDate?: string;
    deathPlace?: string;
    photo?: string;
  };
  children?: D3NodeDatum[];
}

export type ViewMode = 'editor' | 'tree' | 'smart-add';

import React, { useState, useEffect, useRef } from 'react';
import { Person, Gender } from '../types';
import { generateBio } from '../services/geminiService';
import { Wand2, Save, X, Loader2, Heart, Trash2, Camera, Upload, Image as ImageIcon } from 'lucide-react';

interface EditorPanelProps {
  person: Person | null;
  onSave: (person: Person) => void;
  onCancel: () => void;
  allPeople: Person[];
}

export const EditorPanel: React.FC<EditorPanelProps> = ({ person, onSave, onCancel, allPeople }) => {
  const [formData, setFormData] = useState<Partial<Person>>({
    gender: Gender.Male,
    firstName: '',
    lastName: '',
    spouseIds: [],
    childrenIds: [],
  });

  const [generatingBio, setGeneratingBio] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (person) {
      setFormData({ ...person });
    } else {
      // Reset for new entry
      setFormData({
        id: crypto.randomUUID(),
        gender: Gender.Male,
        firstName: '',
        lastName: '',
        spouseIds: [],
        childrenIds: [],
        bio: '',
        birthPlace: '',
        deathPlace: '',
        photo: '',
      });
    }
  }, [person]);

  const handleChange = (field: keyof Person, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (file) {
      // Check file size (limit to ~2MB for browser storage performance)
      if (file.size > 2 * 1024 * 1024) {
        alert("Image is too large. Please choose an image under 2MB.");
        return;
      }

      const reader = new FileReader();
      reader.onloadend = () => {
        handleChange('photo', reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerateBio = async () => {
    if (!formData.firstName || !formData.lastName) return;
    setGeneratingBio(true);
    try {
      const bio = await generateBio(formData as Person);
      handleChange('bio', bio);
    } finally {
      setGeneratingBio(false);
    }
  };

  const addSpouse = (spouseId: string) => {
    if (!spouseId) return;
    const currentSpouses = formData.spouseIds || [];
    if (!currentSpouses.includes(spouseId)) {
        handleChange('spouseIds', [...currentSpouses, spouseId]);
    }
  };

  const removeSpouse = (spouseId: string) => {
    const currentSpouses = formData.spouseIds || [];
    handleChange('spouseIds', currentSpouses.filter(id => id !== spouseId));
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.firstName && formData.lastName) {
        // Ensure arrays are initialized
        const cleanData = {
            ...formData,
            spouseIds: formData.spouseIds || [],
            childrenIds: formData.childrenIds || [],
        }
        onSave(cleanData as Person);
    }
  };

  // Filter potential spouses (exclude self and already selected)
  const availableSpouses = allPeople.filter(p => 
      p.id !== formData.id && 
      !formData.spouseIds?.includes(p.id)
  );

  return (
    <div className="h-full bg-slate-800 border-l border-slate-700 p-6 overflow-y-auto no-scrollbar">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-xl font-bold text-white">
          {person ? 'Edit Person' : 'Add Person'}
        </h2>
        <button onClick={onCancel} className="text-slate-400 hover:text-white">
          <X size={24} />
        </button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">

        {/* Photo Upload Section */}
        <div className="flex flex-col items-center gap-3">
          <div 
            className="relative group w-28 h-28 rounded-full bg-slate-900 border-2 border-slate-600 flex items-center justify-center overflow-hidden cursor-pointer hover:border-brand-500 transition-colors"
            onClick={() => fileInputRef.current?.click()}
          >
            {formData.photo ? (
              <img src={formData.photo} alt="Profile" className="w-full h-full object-cover" />
            ) : (
              <Camera size={32} className="text-slate-500 group-hover:text-brand-400 transition-colors" />
            )}

            {/* Overlay on hover */}
            <div className="absolute inset-0 bg-black/50 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
              <Upload size={20} className="text-white" />
            </div>
          </div>

          <input 
            type="file" 
            ref={fileInputRef} 
            className="hidden" 
            accept="image/*" 
            onChange={handleFileChange} 
          />

          <div className="flex gap-2">
             <button 
                type="button"
                onClick={() => fileInputRef.current?.click()}
                className="text-xs text-brand-400 hover:text-brand-300 font-medium"
             >
               {formData.photo ? 'Change Photo' : 'Upload Photo'}
             </button>
             {formData.photo && (
               <>
                 <span className="text-slate-600">|</span>
                 <button 
                    type="button"
                    onClick={() => handleChange('photo', '')}
                    className="text-xs text-red-400 hover:text-red-300 font-medium"
                 >
                   Remove
                 </button>
               </>
             )}
          </div>
        </div>

        {/* Basic Info */}
        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-xs font-medium text-slate-400 mb-1">First Name</label>
            <input
              type="text"
              required
              className="w-full bg-slate-900 border border-slate-600 rounded px-3 py-2 text-white focus:border-brand-500 outline-none"
              value={formData.firstName || ''}
              onChange={e => handleChange('firstName', e.target.value)}
            />
          </div>
          <div>
            <label className="block text-xs font-medium text-slate-400 mb-1">Last Name</label>
            <input
              type="text"
              required
              className="w-full bg-slate-900 border border-slate-600 rounded px-3 py-2 text-white focus:border-brand-500 outline-none"
              value={formData.lastName || ''}
              onChange={e => handleChange('lastName', e.target.value)}
            />
          </div>
        </div>

        <div>
           <label className="block text-xs font-medium text-slate-400 mb-1">Gender</label>
           <select 
              className="w-full bg-slate-900 border border-slate-600 rounded px-3 py-2 text-white focus:border-brand-500 outline-none"
              value={formData.gender}
              onChange={e => handleChange('gender', e.target.value)}
           >
              <option value={Gender.Male}>Male</option>
              <option value={Gender.Female}>Female</option>
              <option value={Gender.Other}>Other</option>
           </select>
        </div>

        {/* Birth Info */}
        <div className="p-3 bg-slate-900/50 rounded-lg border border-slate-700 space-y-3">
          <h3 className="text-sm font-semibold text-slate-300">Birth Details</h3>
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="block text-xs font-medium text-slate-400 mb-1">Date</label>
              <input
                type="date"
                className="w-full bg-slate-900 border border-slate-600 rounded px-3 py-2 text-white focus:border-brand-500 outline-none"
                value={formData.birthDate || ''}
                onChange={e => handleChange('birthDate', e.target.value)}
              />
            </div>
            <div>
              <label className="block text-xs font-medium text-slate-400 mb-1">Place</label>
              <input
                type="text"
                placeholder="City, Country"
                className="w-full bg-slate-900 border border-slate-600 rounded px-3 py-2 text-white focus:border-brand-500 outline-none"
                value={formData.birthPlace || ''}
                onChange={e => handleChange('birthPlace', e.target.value)}
              />
            </div>
          </div>
        </div>

        {/* Death Info */}
        <div className="p-3 bg-slate-900/50 rounded-lg border border-slate-700 space-y-3">
          <h3 className="text-sm font-semibold text-slate-300">Death Details (Optional)</h3>
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="block text-xs font-medium text-slate-400 mb-1">Date</label>
              <input
                type="date"
                className="w-full bg-slate-900 border border-slate-600 rounded px-3 py-2 text-white focus:border-brand-500 outline-none"
                value={formData.deathDate || ''}
                onChange={e => handleChange('deathDate', e.target.value)}
              />
            </div>
            <div>
              <label className="block text-xs font-medium text-slate-400 mb-1">Place</label>
              <input
                type="text"
                placeholder="City, Country"
                className="w-full bg-slate-900 border border-slate-600 rounded px-3 py-2 text-white focus:border-brand-500 outline-none"
                value={formData.deathPlace || ''}
                onChange={e => handleChange('deathPlace', e.target.value)}
              />
            </div>
          </div>
        </div>

        {/* Relationships */}
        <div className="space-y-3">
            <label className="block text-xs font-medium text-slate-400">Spouses / Partners</label>
            <div className="flex gap-2">
               <select 
                  className="flex-1 bg-slate-900 border border-slate-600 rounded px-3 py-2 text-white outline-none text-sm"
                  onChange={(e) => {
                      addSpouse(e.target.value);
                      e.target.value = "";
                  }}
               >
                  <option value="">+ Add Spouse...</option>
                  {availableSpouses.map(p => (
                      <option key={p.id} value={p.id}>{p.firstName} {p.lastName}</option>
                  ))}
               </select>
            </div>
            <div className="flex flex-wrap gap-2">
                {formData.spouseIds?.map(sid => {
                    const spouse = allPeople.find(p => p.id === sid);
                    if (!spouse) return null;
                    return (
                        <div key={sid} className="bg-slate-700 text-slate-200 px-2 py-1 rounded text-sm flex items-center gap-2">
                            <Heart size={12} className="text-pink-400" />
                            {spouse.firstName} {spouse.lastName}
                            <button type="button" onClick={() => removeSpouse(sid)} className="hover:text-white"><X size={14}/></button>
                        </div>
                    )
                })}
            </div>
        </div>

        {/* Biography */}
        <div>
           <div className="flex justify-between items-end mb-1">
              <label className="block text-xs font-medium text-slate-400">Biography</label>
              <button
                type="button"
                onClick={handleGenerateBio}
                disabled={generatingBio || !formData.firstName}
                className="text-xs flex items-center gap-1 text-brand-400 hover:text-brand-300 disabled:opacity-50"
              >
                {generatingBio ? <Loader2 size={12} className="animate-spin" /> : <Wand2 size={12} />}
                Generate with AI
              </button>
           </div>
           <textarea
              className="w-full bg-slate-900 border border-slate-600 rounded px-3 py-2 text-white focus:border-brand-500 outline-none h-32 text-sm leading-relaxed"
              value={formData.bio || ''}
              onChange={e => handleChange('bio', e.target.value)}
              placeholder="Write a short biography..."
           />
        </div>

        {/* Actions */}
        <div className="pt-4 flex items-center gap-3 border-t border-slate-700">
          <button
            type="submit"
            className="flex-1 bg-brand-600 hover:bg-brand-500 text-white font-medium py-2 rounded-lg transition-colors flex items-center justify-center gap-2"
          >
            <Save size={18} />
            Save Record
          </button>
        </div>
      </form>
    </div>
  );
};

import React, { useMemo } from 'react';
import * as d3 from 'd3';
import { TreeData, Person } from '../types';

interface TreeVisualizerProps {
  data: TreeData;
  onSelectPerson: (id: string) => void;
}

// Helper to convert flat relational data to D3 hierarchy
const buildHierarchy = (data: TreeData): d3.HierarchyNode<any> | null => {
  const { people, rootId } = data;
  const rootPerson = people[rootId];

  if (!rootPerson) return null;

  const buildNode = (personId: string): any => {
    const person = people[personId];
    if (!person) return null;

    const node: any = {
      name: `${person.firstName} ${person.lastName}`,
      attributes: {
        id: person.id,
        gender: person.gender,
        birthDate: person.birthDate,
        birthPlace: person.birthPlace,
        deathDate: person.deathDate,
        deathPlace: person.deathPlace,
        photo: person.photo,
      },
      children: [],
    };

    // Recursively find children
    if (person.childrenIds && person.childrenIds.length > 0) {
      person.childrenIds.forEach(childId => {
        const childNode = buildNode(childId);
        if (childNode) {
          node.children.push(childNode);
        }
      });
    }

    return node;
  };

  const hierarchyData = buildNode(rootId);
  return d3.hierarchy(hierarchyData);
};

export const TreeVisualizer: React.FC<TreeVisualizerProps> = ({ data, onSelectPerson }) => {
  const containerRef = React.useRef<HTMLDivElement>(null);
  const [dimensions, setDimensions] = React.useState({ width: 800, height: 600 });

  React.useEffect(() => {
    if (containerRef.current) {
      setDimensions({
        width: containerRef.current.clientWidth,
        height: containerRef.current.clientHeight
      });
    }

    const handleResize = () => {
       if (containerRef.current) {
        setDimensions({
          width: containerRef.current.clientWidth,
          height: containerRef.current.clientHeight
        });
      }
    };
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const { nodes, links } = useMemo(() => {
    const root = buildHierarchy(data);
    if (!root) return { nodes: [], links: [] };

    // Create a tree layout
    const treeLayout = d3.tree().size([dimensions.width - 100, dimensions.height - 100]);
    treeLayout(root);

    return {
      nodes: root.descendants(),
      links: root.links(),
    };
  }, [data, dimensions]);

  return (
    <div ref={containerRef} className="w-full h-full bg-slate-900 overflow-hidden relative border border-slate-700 rounded-xl shadow-2xl">
      <div className="absolute top-4 right-4 bg-slate-800/80 backdrop-blur p-2 rounded text-xs text-slate-400">
        Start: {data.people[data.rootId]?.firstName} {data.people[data.rootId]?.lastName}
      </div>

      <svg width={dimensions.width} height={dimensions.height} className="cursor-move">
        <defs>
            {/* Standard clip path for images if needed */}
            <clipPath id="circle-clip">
                <circle cx="0" cy="0" r="20" />
            </clipPath>
        </defs>
        <g transform={`translate(50, 50)`}>
          {/* Links */}
          {links.map((link, i) => {
             // Generate a smooth cubic bezier curve
             const d = d3.linkVertical()
                .x((d: any) => d.x)
                .y((d: any) => d.y)
                (link as any);

             const parentName = (link.source.data as any).name;
             const childName = (link.target.data as any).name;

             return (
               <g key={`link-${i}`}>
                   <path
                     d={d || ""}
                     fill="none"
                     stroke="#475569"
                     strokeWidth="2"
                     className="transition-all duration-500"
                   />
                   <title>Parent: {parentName} → Child: {childName}</title>
               </g>
             );
          })}

          {/* Nodes */}
          {nodes.map((node: any, i) => {
             const isMale = node.data.attributes.gender === 'Male';
             const { birthDate, birthPlace, deathDate, deathPlace, photo, id } = node.data.attributes;

             let tooltipText = node.data.name;
             if (birthDate || birthPlace) tooltipText += `\nBorn: ${birthDate || '?'} ${birthPlace ? `in ${birthPlace}` : ''}`;
             if (deathDate || deathPlace) tooltipText += `\nDied: ${deathDate || '?'} ${deathPlace ? `in ${deathPlace}` : ''}`;

             return (
               <g 
                 key={i} 
                 transform={`translate(${node.x},${node.y})`}
                 className="group cursor-pointer"
                 onClick={() => onSelectPerson(id)}
               >
                 <title>{tooltipText}</title>

                 {/* Outer Border / Gender Indicator */}
                 <circle
                   r="24"
                   fill={isMale ? '#0ea5e9' : '#ec4899'}
                   className="transition-all duration-300 shadow-lg"
                 />

                 {/* Photo or Default Circle */}
                 {photo ? (
                    <g>
                        <defs>
                            <clipPath id={`clip-${id}`}>
                                <circle r="20" />
                            </clipPath>
                        </defs>
                        <image
                            href={photo}
                            x="-20"
                            y="-20"
                            width="40"
                            height="40"
                            clipPath={`url(#clip-${id})`}
                            preserveAspectRatio="xMidYMid slice"
                            className="pointer-events-none"
                        />
                        {/* Inner stroke for cleaner edge */}
                        <circle r="20" fill="none" stroke="rgba(0,0,0,0.1)" strokeWidth="1" />
                    </g>
                 ) : (
                    <circle
                        r="20"
                        className="fill-slate-900 stroke-slate-800"
                    />
                 )}

                 <text
                   dy="40"
                   textAnchor="middle"
                   className="fill-slate-300 text-xs font-medium bg-slate-900 pointer-events-none"
                   style={{ textShadow: '0 2px 4px rgba(0,0,0,0.8)' }}
                 >
                   {node.data.name}
                 </text>
                 <text
                   dy="54"
                   textAnchor="middle"
                   className="fill-slate-500 text-[10px] pointer-events-none"
                 >
                   {birthDate?.split('-')[0] || '?'}
                 </text>
               </g>
             );
          })}
        </g>
      </svg>
    </div>
  );
};
